- Create a file named `create-index.js`.

  ```shell
  touch create-index.js
  ```

- Copy and paste the following code to create the index in the
  `create-index.js` file.

  The code does the following:

  - Connects to the cluster and creates an index
    with the specified name for the specified namespace.

  - Indexes the `bsonEmbeddings.float32` and
    `bsonEmbeddings.int8` fields as `vector` type by using
    the `dotProduct` similarity function, and the
    `bsonEmbeddings.int1` field also as `vector` type by
    using the `euclidean` function.

  ```javascript
  import { MongoClient, BSON } from "mongodb";  
  import { setTimeout } from "timers/promises";  

  // Connect to your MongoDB cluster
  const uri = process.env.MONGODB_URI || "<CONNECTION-STRING>";

  const client = new MongoClient(uri);

  async function main() {
    try {
      const DB_NAME = "<DATABASE-NAME>";
      const COLLECTION_NAME = "<COLLECTION-NAME>";
      const db = client.db(DB_NAME);
      const collection = db.collection(COLLECTION_NAME);

      // define your MongoDB Vector Search index
      const index = {
        name: "<INDEX-NAME>",
        type: "vectorSearch",
        definition: {
          fields: [
            {
              type: "vector",
              numDimensions: 1024,
              path: "bsonEmbeddings.float32",
              similarity: "dotProduct",
            },
            {
              type: "vector",
              numDimensions: 1024,
              path: "bsonEmbeddings.int8",
              similarity: "dotProduct",
            },
            {
              type: "vector",
              numDimensions: 1024,
              path: "bsonEmbeddings.int1",
              similarity: "euclidean",
            },
          ],
        },
      };

      // Run the helper method
      const result = await collection.createSearchIndex(index);
      console.log(`New search index named ${result} is building.`);

      // Wait for the index to be ready to query
      console.log("Polling to check if the index is ready. This may take up to a minute.");
      let isQueryable = false;

      // Use filtered search for index readiness
      while (!isQueryable) {
        const [indexData] = await collection.listSearchIndexes(index.name).toArray();

        if (indexData) {
          isQueryable = indexData.queryable;
          if (!isQueryable) {
            await setTimeout(5000); // Wait for 5 seconds before checking again
          }
        } else {
          // Handle the case where the index might not be found
          console.log(`Index ${index.name} not found.`);
          await setTimeout(5000); // Wait for 5 seconds before checking again
        }
      }

      console.log(`${result} is ready for querying.`);
    } catch (error) {
      console.error("Error:", error);
    } finally {
      await client.close();
    }
  }

  main().catch((err) => {
    console.error("Unhandled error:", err);
  });

  ```

- Replace the following settings and save the file.

  | \<CONNECTION-STRING> | Connection string to connect to your Atlas cluster that you want to create the database and collection.Replace this value only if you didn't set the MONGODB\_URI environment variable. |
  | -------------------- | --------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |
  | \<DB-NAME>           | Name of the collection, which is sample\_airbnb.                                                                                                                                        |
  | \<COLLECTION-NAME>   | Name of the collection, which is listingsAndReviews.                                                                                                                                    |
  | \<INDEX-NAME>        | Name of the index for the collection.                                                                                                                                                   |

- Create the index.

  **Input:**

  ```shell
  node create-index.js
  ```

  **Output:**

  ```shell
  New search index named vector_index is building.
  Polling to check if the index is ready. This may take up to a minute.
  <INDEX-NAME> is ready for querying.
  ```

